local function decloak_seed()
  local out = {}
  for i = 1, 32 do
    local m = (0xA5 + (i - 1)) % 256
    m = (m * 0x3D) % 256
    out[i] = bxor(SK[i], m)
  end
  return out
end
local SEED = decloak_seed()

local function u16(b, i)
  return b[i] + b[i+1] * 256
end
local function u32(b, i)
  return b[i] + b[i+1]*256 + b[i+2]*65536 + b[i+3]*16777216
end
local function f64(b, i)
  -- little-endian IEEE754 via string.pack if available
  if string.pack then
    local s = string.char(b[i], b[i+1], b[i+2], b[i+3], b[i+4], b[i+5], b[i+6], b[i+7])
    return string.unpack("<d", s)
  end
  return 0
end

