  -- lightweight 32-byte mixer (NOT cryptographic Blake3; host seal uses real AEAD.
  -- For sealed packages the host pipeline embeds an *opened* or guest-openable blob.
  -- Current emit embeds package bytes as produced by protect (may be sealed).
  -- Open path: if magic sealed sections, apply XOR keystream from SEED.
  local state = {}
  for i = 1, 32 do state[i] = key[i] or 0 end
  for i = 1, #msg do
    local ix = ((i - 1) % 32) + 1
    state[ix] = bxor(state[ix], msg[i])
    state[ix] = band(state[ix] * 33 + i, 255)
  end
  return state
end

local function keystream(domain, n)
  local out = {}
  local counter = 0
  local i = 1
  while i <= n do
    local block = blake3_like(SEED, {string.byte(domain, 1, #domain), counter % 256, rshift(counter, 8) % 256})
    for j = 1, 32 do
      if i > n then break end
      out[i] = block[j]
      i = i + 1
    end
    counter = counter + 1
  end
  return out
end

local function xor_buf(buf, domain)
  local ks = keystream(domain, #buf)
  local out = {}
  for i = 1, #buf do out[i] = bxor(buf[i], ks[i]) end
  return out
end

-- Parse AEG1
local function parse_package(raw)
  local function slice(t, a, b)
    local r = {}
    for i = a, b do r[#r+1] = t[i] end
    return r
  end
  if #(raw) < 28 then error("aegis: package too small") end
  if raw[1] ~= 65 or raw[2] ~= 69 or raw[3] ~= 71 or raw[4] ~= 49 then
    error("aegis: bad magic")
  end
  local version = u16(raw, 5)
  local flags = u32(raw, 7)
  local sid = slice(raw, 11, 26)
  local nsec = u16(raw, 27)
  local i = 29
  local sections = {}
  for s = 1, nsec do
    local kind = raw[i]; i = i + 1
    local len = u32(raw, i); i = i + 4
    local data = slice(raw, i, i + len - 1)
    i = i + len
    sections[#sections+1] = {kind = kind, data = data}
  end
  return {version = version, flags = flags, session = sid, sections = sections}
end

local function decode_constants(data)
  local n = u32(data, 1)
  local i = 5
  local out = {}
  for _ = 1, n do
    local tag = data[i]; i = i + 1
    if tag == 0 then out[#out+1] = nil
    elseif tag == 1 then out[#out+1] = false
    elseif tag == 2 then out[#out+1] = true
    elseif tag == 3 then
      out[#out+1] = f64(data, i); i = i + 8
    elseif tag == 4 then
      local len = u32(data, i); i = i + 4
      local chars = {}
      for j = 0, len - 1 do chars[j+1] = string.char(data[i+j]) end
      out[#out+1] = table.concat(chars)
      i = i + len
    else
      error("aegis: bad const tag")
    end
  end
  return out
end

local function decode_functions(data)
  local n = u32(data, 1)
  local i = 5
  local out = {}
  for _ = 1, n do
    local id = u32(data, i); i = i + 4
    local nparams = u16(data, i); i = i + 2
    local is_vararg = data[i] ~= 0; i = i + 1
    local nregs = u16(data, i); i = i + 2
    local nup = u16(data, i); i = i + 2
    local ups = {}
    for u = 1, nup do
      local instack = data[i] ~= 0; i = i + 1
      local idx = u16(data, i); i = i + 2
      ups[u] = {instack = instack, index = idx}
    end
    local nblocks = u16(data, i); i = i + 2
    local blocks = {}
    for b = 1, nblocks do
      blocks[b] = u32(data, i); i = i + 4
    end
    local clen = u32(data, i); i = i + 4
    local code = {}
    for c = 0, clen - 1 do code[c+1] = data[i+c] end
    i = i + clen
    local has_name = data[i]; i = i + 1
    if has_name ~= 0 then
      local nl = u16(data, i); i = i + 2
      i = i + nl
    end
    out[#out+1] = {
      id = id, nparams = nparams, is_vararg = is_vararg, nregs = nregs,
      upvalues = ups, block_offs = blocks, code = code
    }
  end
  return out
end

local pkg = parse_package(PKG)
local opcode_map, constants, functions
for _, sec in ipairs(pkg.sections) do
  if sec.kind == 1 then
    opcode_map = sec.data
  elseif sec.kind == 2 then
    local data = sec.data
    if band(pkg.flags, 1) ~= 0 then
      -- sealed const section: open with AEAD is host-only; pipeline embeds unsealed for guest
      -- or XOR-stream fallback for demo compatibility
      data = xor_buf(data, "aegis-const-section-v1")
    end
    constants = decode_constants(data)
  elseif sec.kind == 3 then
    local data = sec.data
    if band(pkg.flags, 1) ~= 0 then
      data = xor_buf(data, "aegis-code-section-v1")
    end
    functions = decode_functions(data)
  end
end
if not opcode_map or not functions then error("aegis: incomplete package") end
constants = constants or {}

-- wire -> logical: opcode_map[logical+1] = wire, build reverse
local wire_to_logical = {}
for logical = 0, #opcode_map - 1 do
  local wire = opcode_map[logical + 1]
  wire_to_logical[wire] = logical
end

local function decode_stream(code)
  local insts = {}
  local i = 1
  while i <= #code do
    local offset = i - 1
    local wire = code[i]; i = i + 1
    local fmt_byte = code[i]; i = i + 1
    local fmt = bxor(fmt_byte, band(wire * 0x5D, 255))
    local op = wire_to_logical[wire]
    local a, b, c, aux = 0, 0, 0, 0
    if fmt == 0 then
      -- nil
    elseif fmt == 1 then
      a = code[i]; i = i + 1
    elseif fmt == 2 then
      a = code[i]; b = code[i+1]; i = i + 2
    elseif fmt == 3 then
      a = code[i]; b = code[i+1]; c = code[i+2]; i = i + 3
    elseif fmt == 6 then
      a = u16(code, i); b = u16(code, i+2); c = u16(code, i+4); aux = u32(code, i+6); i = i + 10
    else
      error("aegis: bad fmt "..tostring(fmt))
    end
    insts[#insts+1] = {op = op, a = a, b = b, c = c, aux = aux, offset = offset}
  end
  return insts
end

-- Prepare protos
local protos = {}
for pi, f in ipairs(functions) do
  local insts = decode_stream(f.code)
  local pc_of = {}
  for idx, ins in ipairs(insts) do
    pc_of[ins.offset] = idx
  end
  protos[pi] = {meta = f, insts = insts, pc_of = pc_of}
end

local OP = {
  Mov=0, LoadNil=1, LoadTrue=2, LoadFalse=3, LoadK=4, LoadEnv=5, StoreEnv=6,
  GetUpval=7, SetUpval=8, Add=18, Sub=19, Mul=20, Div=21, Mod=22, Pow=23, IDiv=24, Concat=25,
  Neg=26, Len=27, Band=46, Bor=47, Bxor=48, Bnot=49, Shl=50, Shr=51,
  Eq=58, Ne=59, Lt=60, Le=61, Gt=62, Ge=63, TestNot=67,
  Jmp=78, JmpT=79, JmpF=80, Ret=89, Ret0=90, Ret1=91, RetV=92, TailCall=93, Call=94, Call0=95, Call1=96,
  NewTable=102, GetTable=103, SetTable=104, Closure=124, CloseUpvals=125,
  GetUp0=127, GetUp1=128, SetUp0=129, SetUp1=130, Closure0=131, Closure1=132,
  NewTable0=113, NewArray=114, LoadImm=13, Clear=12, MovN=11, Nop=17,
}

local function is_truthy(v)
  return v ~= nil and v ~= false
end

local function as_num(v)
  local t = type(v)
  if t == "number" then return v end
  if t == "string" then return tonumber(v) or 0 end
  if t == "boolean" then return v and 1 or 0 end
  return 0
end

local env = _ENV
local function get_global(name)
  return env[name]
end
local function set_global(name, val)
  env[name] = val
end

local function run_proto(pi, args, upvalues)
  local P = protos[pi + 1]
  if not P then error("aegis: bad proto") end
  local regs = {}
  for i = 1, math.max(P.meta.nregs, 1) do regs[i] = nil end
  for i = 1, #(args or {}) do regs[i] = args[i] end
  local ups = upvalues or {}
  local pc = 1
  local steps = 0
  while pc <= #P.insts do
    steps = steps + 1
    if steps > 50000000 then error("aegis: budget") end
    local ins = P.insts[pc]
    pc = pc + 1
    local op, a, b, c, aux = ins.op, ins.a, ins.b, ins.c, ins.aux
    -- specialized aliases
    if op == OP.Nop or op == 196 or op == 197 or op == 198 then
      -- nop
    elseif op == OP.Mov or op == OP.MovN then
      regs[a+1] = regs[b+1]
    elseif op == OP.LoadNil or op == OP.Clear then
      regs[a+1] = nil
    elseif op == OP.LoadTrue then regs[a+1] = true
    elseif op == OP.LoadFalse then regs[a+1] = false
    elseif op == OP.LoadK then regs[a+1] = constants[aux+1]
    elseif op == OP.LoadImm then
      local imm = aux % 65536
      if imm >= 32768 then imm = imm - 65536 end
      regs[a+1] = imm
    elseif op == OP.LoadEnv then
      local name = constants[aux+1]
      regs[a+1] = get_global(name)
    elseif op == OP.StoreEnv then
      local name = constants[aux+1]
      set_global(name, regs[a+1])
    elseif op == OP.GetUpval or op == OP.GetUp0 or op == OP.GetUp1 then
      local idx = (op == OP.GetUp0 and 0) or (op == OP.GetUp1 and 1) or b
      local cell = ups[idx+1]
      regs[a+1] = cell and cell[1] or nil
    elseif op == OP.SetUpval or op == OP.SetUp0 or op == OP.SetUp1 then
      local idx = (op == OP.SetUp0 and 0) or (op == OP.SetUp1 and 1) or b
      local cell = ups[idx+1]
      if cell then cell[1] = regs[a+1] end
    elseif op == OP.Add then regs[a+1] = as_num(regs[b+1]) + as_num(regs[c+1])
    elseif op == OP.Sub then regs[a+1] = as_num(regs[b+1]) - as_num(regs[c+1])
    elseif op == OP.Mul then regs[a+1] = as_num(regs[b+1]) * as_num(regs[c+1])
    elseif op == OP.Div then regs[a+1] = as_num(regs[b+1]) / as_num(regs[c+1])
    elseif op == OP.Mod then regs[a+1] = as_num(regs[b+1]) % as_num(regs[c+1])
    elseif op == OP.Pow then regs[a+1] = as_num(regs[b+1]) ^ as_num(regs[c+1])
    elseif op == OP.IDiv then regs[a+1] = math.floor(as_num(regs[b+1]) / as_num(regs[c+1]))
    elseif op == OP.Concat then regs[a+1] = tostring(regs[b+1] or "") .. tostring(regs[c+1] or "")
    elseif op == OP.Neg then regs[a+1] = -as_num(regs[b+1])
    elseif op == OP.Len then
      local v = regs[b+1]
      regs[a+1] = (type(v) == "string" and #v) or (type(v) == "table" and #v) or 0
    elseif op == OP.TestNot then regs[a+1] = not is_truthy(regs[b+1])
    elseif op == OP.Band then regs[a+1] = band(as_num(regs[b+1]), as_num(regs[c+1]))
    elseif op == OP.Bor then regs[a+1] = bor(as_num(regs[b+1]), as_num(regs[c+1]))
    elseif op == OP.Bxor then regs[a+1] = bxor(as_num(regs[b+1]), as_num(regs[c+1]))
    elseif op == OP.Bnot then regs[a+1] = bxor(as_num(regs[b+1]), -1)
    elseif op == OP.Shl then regs[a+1] = lshift(as_num(regs[b+1]), as_num(regs[c+1]))
    elseif op == OP.Shr then regs[a+1] = rshift(as_num(regs[b+1]), as_num(regs[c+1]))
    elseif op == OP.Eq then regs[a+1] = regs[b+1] == regs[c+1]
    elseif op == OP.Ne then regs[a+1] = regs[b+1] ~= regs[c+1]
    elseif op == OP.Lt then regs[a+1] = as_num(regs[b+1]) < as_num(regs[c+1])
    elseif op == OP.Le then regs[a+1] = as_num(regs[b+1]) <= as_num(regs[c+1])
    elseif op == OP.Gt then regs[a+1] = as_num(regs[b+1]) > as_num(regs[c+1])
    elseif op == OP.Ge then regs[a+1] = as_num(regs[b+1]) >= as_num(regs[c+1])
    elseif op == OP.NewTable or op == OP.NewTable0 or op == OP.NewArray then
      regs[a+1] = {}
    elseif op == OP.GetTable then
      local t = regs[b+1]
      regs[a+1] = type(t) == "table" and t[regs[c+1]] or nil
    elseif op == OP.SetTable then
      local t = regs[a+1]
      if type(t) == "table" then t[regs[b+1]] = regs[c+1] end
    elseif op == OP.Closure or op == OP.Closure0 or op == OP.Closure1 then
      local fid = aux
      local child = protos[fid + 1]
      local cups = {}
      if child then
        for ui, u in ipairs(child.meta.upvalues) do
          if u.instack then
            cups[ui] = {regs[u.index + 1]}
          else
            cups[ui] = ups[u.index + 1] or {nil}
          end
        end
      end
      regs[a+1] = {__aegis_closure = true, proto = fid, ups = cups}
    elseif op == OP.Call or op == OP.Call0 or op == OP.Call1 then
      local base = a
      local narg = b
      local nret = c
      local callee = regs[base + 1]
      local cargs = {}
      for i = 1, narg do cargs[i] = regs[base + 1 + i] end
      local rets
      if type(callee) == "table" and callee.__aegis_closure then
        rets = {run_proto(callee.proto, cargs, callee.ups)}
      elseif type(callee) == "function" then
        rets = {callee(table.unpack(cargs))}
      else
        error("aegis: call of non-function")
      end
      local want = nret
      if want == 0xFFFF then want = #rets end
      for i = 1, want do regs[base + i] = rets[i] end
    elseif op == OP.TailCall then
      local base = a
      local narg = b
      local callee = regs[base + 1]
      local cargs = {}
      for i = 1, narg do cargs[i] = regs[base + 1 + i] end
      if type(callee) == "table" and callee.__aegis_closure then
        return run_proto(callee.proto, cargs, callee.ups)
      elseif type(callee) == "function" then
        return callee(table.unpack(cargs))
      else
        error("aegis: tailcall")
      end
    elseif op == OP.Ret0 then
      return
    elseif op == OP.Ret1 then
      return regs[a+1]
    elseif op == OP.Ret then
      local n = b
      local o = {}
      for i = 0, n - 1 do o[i+1] = regs[a + 1 + i] end
      return table.unpack(o)
    elseif op == OP.RetV then
      return regs[a+1]
    elseif op == OP.Jmp then
      -- B = basic-block index
      local bo = P.meta.block_offs[b + 1]
      pc = (bo and P.pc_of[bo]) or pc
    elseif op == OP.JmpT or op == OP.JmpF then
      local cond = is_truthy(regs[a+1])
      if op == OP.JmpF then cond = not cond end
      local bi = cond and b or c
      local bo = P.meta.block_offs[bi + 1]
      pc = (bo and P.pc_of[bo]) or pc
    elseif op == OP.CloseUpvals then
      -- nop
    else
      -- treat unknown as nop (poly decoys)
    end
  end
end

return run_proto(0, {}, {})
